cache-inspect-hit.script:
report() {
  printf '%s\n' "$1" >> reports/cache-inspect-hit.log
}

mkdir -p reports cached
test -f cached/payload.txt || {
  echo '[ERROR] expected cache payload is missing'
  exit 1
}
grep -F 'produced-by=cache-produce-payload' cached/payload.txt || {
  echo '[ERROR] cache payload producer mismatch'
  exit 1
}
report 'cache-hit'
report "payload=$(tr '\n' ';' < cached/payload.txt)"

cache-clear-second.script:
report() {
  printf '%s\n' "$1" >> reports/cache-clear-second.log
}

mkdir -p reports cached
rm -f cached/payload.txt
report 'payload-removed'

verify-cache-roundtrip.script:
test -f reports/cache-clear-initial.log || {
  echo '[ERROR] missing initial clear report'
  exit 1
}
test -f reports/cache-produce-payload.log || {
  echo '[ERROR] missing cache producer report'
  exit 1
}
test -f reports/cache-inspect-hit.log || {
  echo '[ERROR] missing cache hit report'
  exit 1
}
test -f reports/cache-clear-second.log || {
  echo '[ERROR] missing second clear report'
  exit 1
}
test -f reports/cache-inspect-empty.log || {
  echo '[ERROR] missing empty-cache report'
  exit 1
}

grep -F 'cleared-initial' reports/cache-clear-initial.log || {
  echo '[ERROR] initial clear marker mismatch'
  exit 1
}
grep -F 'payload-created' reports/cache-produce-payload.log || {
  echo '[ERROR] payload creation marker mismatch'
  exit 1
}
grep -F 'cache-hit' reports/cache-inspect-hit.log || {
  echo '[ERROR] cache hit marker mismatch'
  exit 1
}
grep -F 'payload-removed' reports/cache-clear-second.log || {
  echo '[ERROR] second clear marker mismatch'
  exit 1
}
grep -F 'cache-empty' reports/cache-inspect-empty.log || {
  echo '[ERROR] empty cache marker mismatch'
  exit 1
}
